// Parse JSONL to array of examples for few-shot use
export interface GoldenQAExample {
  user: string;
  assistant: string;
}

export function parseGoldenQA(): GoldenQAExample[] {
  return MMC_COPILOT_GOLDEN_QA_JSONL
    .split('\n')
    .filter(line => line.trim())
    .map(line => JSON.parse(line));
}

// Get formatted few-shot examples for prompt injection
export function getFewShotExamples(count: number = 5): string {
  const examples = parseGoldenQA().slice(0, count);
  return examples
    .map(ex => `User: ${ex.user}\nAssistant: ${ex.assistant}`)
    .join('\n\n---\n\n');
}

// Get random examples for variety
export function getRandomFewShotExamples(count: number = 5): string {
  const all = parseGoldenQA();
  const shuffled = [...all].sort(() => Math.random() - 0.5);
  return shuffled
    .slice(0, count)
    .map(ex => `User: ${ex.user}\nAssistant: ${ex.assistant}`)
    .join('\n\n---\n\n');
}

// Get examples by category/topic
export function getExamplesByTopic(topic: string, count: number = 3): GoldenQAExample[] {
  const all = parseGoldenQA();
  const topicLower = topic.toLowerCase();
  return all
    .filter(ex => 
      ex.user.toLowerCase().includes(topicLower) || 
      ex.assistant.toLowerCase().includes(topicLower)
    )
    .slice(0, count);
}

